import React, { useState } from "react";
import axios from "axios";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend, Filler);

const IndianStockDetails = () => {
  const [symbol, setSymbol] = useState("TCS.NS");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");

  const fetchData = async () => {
    setError("");
    try {
      const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      setError("Failed to fetch stock data.");
      console.error(err);
    }
  };

  const renderMetric = (label, value, isCurrency = false) => (
    <li>
      <strong>{label}:</strong>{" "}
      {value ? (isCurrency ? `₹${Number(value).toLocaleString()}` : value) : "N/A"}
    </li>
  );

  const renderChart = () => {
    if (!data?.historical?.length) return null;

    const labels = data.historical.map((d) =>
      new Date(d.date).toLocaleDateString("en-IN", { month: "short", day: "numeric" })
    );
    const prices = data.historical.map((d) => d.close);

    return (
      <Line
        data={{
          labels,
          datasets: [
            {
              label: `${data.symbol} Closing Price`,
              data: prices,
              borderColor: "blue",
              backgroundColor: "rgba(0, 0, 255, 0.1)",
              tension: 0.3,
              fill: true,
            },
          ],
        }}
        options={{
          plugins: { legend: { display: false } },
          responsive: true,
        }}
      />
    );
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h2>📈 Indian Stock Details</h2>
      <input
        type="text"
        value={symbol}
        onChange={(e) => setSymbol(e.target.value)}
        placeholder="Enter Symbol (e.g., TCS.NS)"
        style={{ padding: "8px", width: "250px" }}
      />
      <button onClick={fetchData} style={{ marginLeft: "10px", padding: "8px" }}>
        Get Details
      </button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <>
          <h3>{data.name} ({data.symbol})</h3>
          <h1 style={{ color: data.change > 0 ? "green" : "red" }}>
            ₹{data.price} | Change: {data.change} ({data.percentChange}%)
          </h1>

          <h4>📌 Key Metrics</h4>
          <ul>
            {renderMetric("EPS", data.eps)}
            {renderMetric("ROE (%)", data.roe)}
            {renderMetric("Book Value", data.bookValue, true)}
            {renderMetric("Face Value", data.faceValue, true)}
            {renderMetric("PE Ratio", data.peRatio)}
            {renderMetric("Dividend Yield (%)", data.dividendYield)}
            {renderMetric("ROCE (%)", data.roce)}
            {renderMetric("Market Cap", data.marketCap, true)}
            {renderMetric("52 Week High", data.fiftyTwoWeekHigh, true)}
            {renderMetric("52 Week Low", data.fiftyTwoWeekLow, true)}
          </ul>

          {renderChart()}

          <h4>👨‍👩‍👧‍👦 Peers</h4>
          <ul>
            {data.peers?.map((peer, i) => (
              <li key={i}>{peer}</li>
            )) || <p>No data</p>}
          </ul>

          <h4>✅ Pros</h4>
          <ul>
            {data.pros?.map((p, i) => <li key={i}>{p}</li>) || <li>No pros found.</li>}
          </ul>

          <h4>❌ Cons</h4>
          <ul>
            {data.cons?.map((c, i) => <li key={i}>{c}</li>) || <li>No cons found.</li>}
          </ul>

          <h4>📄 Balance Sheet</h4>
          <table border="1" cellPadding="5" style={{ marginBottom: "20px" }}>
            <thead>
              <tr>
                <th>Year</th>
                <th>Total Assets</th>
                <th>Total Liabilities</th>
                <th>Equity</th>
              </tr>
            </thead>
            <tbody>
              {data.balanceSheet?.map((item, i) => (
                <tr key={i}>
                  <td>{item.year}</td>
                  <td>₹{item.assets}</td>
                  <td>₹{item.liabilities}</td>
                  <td>₹{item.equity}</td>
                </tr>
              ))}
            </tbody>
          </table>

          <h4>📄 Profit & Loss</h4>
          <table border="1" cellPadding="5">
            <thead>
              <tr>
                <th>Year</th>
                <th>Revenue</th>
                <th>Profit</th>
              </tr>
            </thead>
            <tbody>
              {data.profitLoss?.map((item, i) => (
                <tr key={i}>
                  <td>{item.year}</td>
                  <td>₹{item.revenue}</td>
                  <td>₹{item.profit}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </>
      )}
    </div>
  );
};

export default IndianStockDetails;
